    #[test]
    fn test_sequencing_ordering_priority() {
        let sel_a = fixed_bytes!("11111111");
        let sel_b = fixed_bytes!("22222222");

        let mut set_a = SelectorSet::new();
        set_a.insert(sel_a);

        let mut set_b = SelectorSet::new();
        set_b.insert(sel_b);

        let ordering = SequencingOrdering::new(vec![set_a.clone(), set_b.clone()]);

        assert_eq!(ordering.get_priority(&set_a), Some(Priority::new(0)));
        assert_eq!(ordering.get_priority(&set_b), Some(Priority::new(1)));

