    #[test]
    fn test_contract_interaction_new() {
        let contract = Address::repeat_byte(0x42);
        let mut selectors = SelectorSet::new();
        selectors.insert(fixed_bytes!("11223344"));

        let interaction = ContractInteraction::new(contract, selectors.clone());

        assert_eq!(interaction.contract, contract);
        assert_eq!(interaction.selectors, selectors);
    }

